// handle_telegram_reply.py prints exactly one JSON line on stdout.
// status: 'ignored' (not yes/no, or nothing pending — not an error),
// 'pending_approval' (regenerated, resent to Telegram), 'published'
// (animated + gated + published), 'flagged' (gave up or a stage failed),
// 'error' (infra problem — URL not consumed, will still be actionable
// next time). The `|| true` in the command keeps n8n from aborting.
const raw = ($json.stdout || '').trim();
let parsed = { status: 'error', error: 'handler produced no stdout', stderr: ($json.stderr || '').slice(-1500) };
const jsonLines = raw.split('\n').filter((l) => l.trim().startsWith('{'));
if (jsonLines.length) {
  try {
    parsed = JSON.parse(jsonLines[jsonLines.length - 1]);
  } catch (e) {
    parsed = { status: 'error', error: 'unparseable handler output', raw, stderr: ($json.stderr || '').slice(-1500) };
  }
}
return [{ json: parsed }];
